import React, { useEffect, useState } from 'react';
import { Table, TableBody, TableCell, TableHead, TableRow, Button, TextField, Box, Typography, CircularProgress } from '@material-ui/core';
import { getCategories, createCategory, updateCategory, deleteCategory } from '../services/ApiService';
import { makeStyles } from '@material-ui/core/styles';

const useStyles = makeStyles((theme) => ({
  root: {
    padding: theme.spacing(3),
  },
  form: {
    display: 'flex',
    gap: theme.spacing(2),
    marginBottom: theme.spacing(2),
  },
}));

export default function CategoryManagement() {
  const classes = useStyles();
  const [categories, setCategories] = useState([]);
  const [newCategory, setNewCategory] = useState({ name: '' });
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    setLoading(true);
    getCategories().then(res => {
      if (res.error) {
        setError('Failed to load categories');
      } else {
        setCategories(res.data);
      }
      setLoading(false);
    });
  }, []);

  const addCategory = () => {
    createCategory(newCategory).then(res => {
      if (!res.error) {
        setCategories([...categories, res.data]);
        setNewCategory({ name: '' });
      } else {
        setError('Failed to create category');
      }
    });
  };

  const handleUpdate = (id, category) => {
    updateCategory(id, category).then(res => {
      if (!res.error) {
        setCategories(categories.map(c => (c.id === id ? res.data : c)));
      } else {
        setError('Failed to update category');
      }
    });
  };

  const handleDelete = (id) => {
    deleteCategory(id).then(res => {
      if (!res.error) {
        setCategories(categories.filter(c => c.id !== id));
      } else {
        setError('Failed to delete category');
      }
    });
  };

  if (loading) return <CircularProgress />;
  if (error) return <Typography color="error">{error}</Typography>;

  return (
    <div className={classes.root}>
      <Typography variant="h4" gutterBottom>Category Management</Typography>
      <Box className={classes.form}>
        <TextField
          label="Category Name"
          value={newCategory.name}
          onChange={e => setNewCategory({ ...newCategory, name: e.target.value })}
        />
        <Button onClick={addCategory} color="primary" variant="contained">Add Category</Button>
      </Box>
      <Table>
        <TableHead>
          <TableRow>
            <TableCell>Name</TableCell>
            <TableCell>Actions</TableCell>
          </TableRow>
        </TableHead>
        <TableBody>
          {categories.map(category => (
            <TableRow key={category.id}>
              <TableCell>{category.name}</TableCell>
              <TableCell>
                <Button onClick={() => handleUpdate(category.id, { ...category, name: category.name + ' Updated' })} color="primary">Update</Button>
                <Button onClick={() => handleDelete(category.id)} color="secondary">Delete</Button>
              </TableCell>
            </TableRow>
          ))}
        </TableBody>
      </Table>
    </div>
  );
}
